(function(e) {
    e.PluginManager.add("textshadow", function(t, n, r) {
        t.on("init", function() {
            t.formatter.register({
                textshadow: {
                    inline: "span",
                    styles: {
                        "text-shadow": "%value"
                    }
                }
            })
        });
        t.addButton("textshadowselect", function() {
            var n = [],
                r = "1px 1px rgba(255,255,255,0.4)|2px 2px rgba(255,255,255,0.4)|3px 3px rgba(255,255,255,0.4)|1px 1px rgba(0,0,0,0.4)|2px 2px rgba(0,0,0,0.4)|3px 3px rgba(0,0,0,0.4)|1px 1px rgba(128,128,128,0.4)|2px 2px rgba(128,128,128,0.4)|3px 3px rgba(128,128,128,0.4)|none";
            var i = t.settings.textshadow_formats || r;
            i.split("|").forEach(function(e) {
                var t = e,
                    r = e;
                var i = e.split("=");
                if (i.length > 1) {
                    t = i[0];
                    r = i[1]
                }
                n.push({
                    text: t,
                    value: r
                })
            });
            return {
                type: "listbox",
                text: "Text Shadow",
                tooltip: "Text Shadow",
                values: n,
                fixedWidth: true,
                onPostRender: function() {
                    var e = this;
                    t.on("nodeChange", function(r) {
                        var i = "textshadow";
                        var s = t.formatter;
                        var o = null;
                        r.parents.forEach(function(e) {
                            n.forEach(function(t) {
                                if (i) {
                                    if (s.matchNode(e, i, {
                                            value: t.value
                                        })) {
                                        o = t.value
                                    }
                                } else {
                                    if (s.matchNode(e, t.value)) {
                                        o = t.value
                                    }
                                }
                                if (o) {
                                    return false
                                }
                            });
                            if (o) {
                                return false
                            }
                        });
                        e.value(o)
                    })
                },
                onselect: function(t) {
                    e.activeEditor.formatter.apply("textshadow", {
                        value: this.value()
                    })
                }
            }
        })
    });
    e.PluginManager.requireLangPack("textshadow", "de")
})(tinymce)